import pdfMake from "pdfmake/build/pdfmake";
import * as pdfFonts from "pdfmake/build/vfs_fonts";

pdfMake.vfs = pdfFonts.vfs;

export function NumerolojiPdf(data) {
  // Base64 arkaplan resmi - buraya kendi base64 kodunuzu ekleyin
 const backgroundImageBase64 = "data:image/jpeg;base64,"; // Base64 kodunuzu buraya yapıştırın

  // Define custom colors
  const colors = {
    primary: '#6A0DAD',
    secondary: '#9C27B0',
    accent: '#E1BEE7',
    light: '#F3E5F5',
    dark: '#4B0082',
    text: '#333333'
  };

  const docDefinition = {
    pageSize: 'A4',
    pageMargins: [40, 60, 40, 60],
    defaultStyle: {
      font: "Roboto",
      fontSize: 12,
      color: colors.text
    },

    header: function (currentPage, pageCount) {
      if (currentPage === 1) {
        return {
          stack: [
            {
              text: "✨ NUMEROLOJİ ANALİZ RAPORU",
              style: "mainHeader",
              alignment: "center",
              margin: [0, 20, 0, 10]
            },
            {
              canvas: [{ type: 'line', x1: 40, y1: 5, x2: 555, y2: 5, lineWidth: 2, lineColor: colors.primary }]
            }
          ]
        };
      }

      return {
        stack: [
          {
            text: "Numeroloji Analiz Raporu",
            style: "pageHeader",
            alignment: "center",
            margin: [0, 20, 0, 5]
          },
          {
            canvas: [{ type: 'line', x1: 40, y1: 5, x2: 555, y2: 5, lineWidth: 1, lineColor: colors.secondary }]
          }
        ]
      };
    },

    footer: function (currentPage, pageCount) {
      return {
        stack: [
          {
            canvas: [{ type: 'line', x1: 40, y1: 5, x2: 555, y2: 5, lineWidth: 1, lineColor: colors.secondary }]
          },
          {
            text: `Sayfa ${currentPage} / ${pageCount}`,
            alignment: "center",
            fontSize: 9,
            margin: [0, 5, 0, 0],
            color: colors.dark
          },
          {
            text: `© ${new Date().getFullYear()} -  - Mucizevi Gelişim`,
            alignment: "center",
            fontSize: 8,
            color: colors.secondary,
            margin: [0, 5, 0, 10]
          }
        ]
      };
    },

    background: function (currentPage) {
      if (currentPage === 1) {
        return {
          image: backgroundImageBase64,
          width: 595,
          height: 842,
          absolutePosition: { x: 0, y: 0 }
        };
      }
      return null;
    },

    content: [
      // KAPAK SAYFASI
      {
        stack: [
          { text: "NUMEROLOJİ ANALİZ RAPORU", style: "coverTitle" },
          { text: "Yaşam Yolunuzun Şifreleri", style: "coverSubtitle" },
          { text: "\n" },
          {
            table: {
              widths: ['*'],
              body: [
                [{ text: `${data.firstName} ${data.lastName}`, style: "coverName" }],
                [{ text: `Doğum Tarihi: ${data.birthDay}.${data.birthMonth}.${data.birthYear}`, style: "coverDate" }]
              ]
            },
            layout: 'noBorders',
            margin: [0, 30, 0, 0]
          },
          { text: "\n\n\n" },
          {
            text: "Bu rapor kişiye özel hazırlanmıştır ve gizlidir.",
            style: "coverFooter",
            alignment: "center",
            margin: [0, 100, 0, 0]
          },
          {
            text: `Oluşturulma Tarihi: ${new Date().toLocaleDateString('tr-TR')}`,
            style: "coverDate",
            alignment: "center"
          }
        ],
        pageBreak: 'after'
      },

      // KİŞİSEL BİLGİLER SAYFASI
      {
        stack: [
          { text: "Kişisel Bilgiler", style: "sectionHeader" },
          { text: "\n" },
          {
            style: "infoBox",
            table: {
              widths: [150, '*'],
              body: [
                [
                  { text: "İsim Soyisim", style: "tableHeader" },
                  { text: `${data.firstName} ${data.lastName}`, style: "tableValue" }
                ],
                [
                  { text: "Doğum Tarihi", style: "tableHeader" },
                  { text: `${data.birthDay}.${data.birthMonth}.${data.birthYear}`, style: "tableValue" }
                ],
                [
                  { text: "E-posta", style: "tableHeader" },
                  { text: data.email || "Belirtilmemiş", style: "tableValue" }
                ],
                [
                  { text: "Rapor Tarihi", style: "tableHeader" },
                  { text: data.currentDate, style: "tableValue" }
                ]
              ]
            },
            layout: {
              defaultBorder: false,
              fillColor: function (rowIndex) {
                return (rowIndex % 2 === 0) ? '#F3E5F5' : null;
              }
            }
          },
          { text: "\n\n" },
          {
            text: "Numeroloji, sayıların sembolik anlamlarını inceleyerek kişilik özelliklerini, potansiyelleri ve yaşam yolunu anlamaya yardımcı olan kadim bir bilgelik öğretisidir. Bu rapor, doğum tarihinizden ve isminizden elde edilen sayısal değerlerin analizine dayanmaktadır.",
            style: "infoText",
            margin: [0, 0, 0, 20]
          }
        ],
        pageBreak: 'after'
      },

      // NUMEROLOJİ SONUÇLARI SAYFASI
      {
        stack: [
          { text: "Numeroloji Analiz Sonuçları", style: "sectionHeader" },
          { text: "\n" },
          
          // Yaşam Yolu Sayısı
          {
            stack: [
              { text: "1. Yaşam Yolu Sayısı", style: "subsectionHeader" },
              {
                stack: [
                  {
                    text: data.lifePathNumber.toString(),
                    style: "numberCircle",
                    alignment: "center"
                  },
                  {
                    text: "Doğum tarihinize göre hesaplanır",
                    style: "numberLabel",
                    alignment: "center"
                  }
                ],
                alignment: "center",
                margin: [0, 0, 0, 10]
              },
              {
                text: data.lifePathMeaning,
                style: "meaningText"
              }
            ],
            margin: [0, 0, 0, 20]
          },

          // İfade/İsim Sayısı
          {
            stack: [
              { text: "2. İfade/İsim Sayısı", style: "subsectionHeader" },
              {
                stack: [
                  {
                    text: data.expressionNumber.toString(),
                    style: "numberCircle",
                    alignment: "center"
                  },
                  {
                    text: "Tam isminize göre hesaplanır",
                    style: "numberLabel",
                    alignment: "center"
                  }
                ],
                alignment: "center",
                margin: [0, 0, 0, 10]
              },
              {
                text: data.expressionMeaning,
                style: "meaningText"
              }
            ],
            margin: [0, 0, 0, 20]
          },

          // Ruh Arzusu Sayısı
          {
            stack: [
              { text: "3. Ruh Arzusu Sayısı", style: "subsectionHeader" },
              {
                stack: [
                  {
                    text: data.soulUrgeNumber.toString(),
                    style: "numberCircle",
                    alignment: "center"
                  },
                  {
                    text: "İsimdeki ünlü harflere göre hesaplanır",
                    style: "numberLabel",
                    alignment: "center"
                  }
                ],
                alignment: "center",
                margin: [0, 0, 0, 10]
              },
              {
                text: data.soulUrgeMeaning,
                style: "meaningText"
              }
            ],
            margin: [0, 0, 0, 20]
          },

          // Kişilik Sayısı
          {
            stack: [
              { text: "4. Kişilik Sayısı", style: "subsectionHeader" },
              {
                stack: [
                  {
                    text: data.personalityNumber.toString(),
                    style: "numberCircle",
                    alignment: "center"
                  },
                  {
                    text: "İsimdeki ünsüz harflere göre hesaplanır",
                    style: "numberLabel",
                    alignment: "center"
                  }
                ],
                alignment: "center",
                margin: [0, 0, 0, 10]
              },
              {
                text: data.personalityMeaning,
                style: "meaningText"
              }
            ],
            margin: [0, 0, 0, 20]
          }
        ],
        pageBreak: 'after'
      },

      // KARMİK ANALİZ SAYFASI
      {
        stack: [
          { text: "Karmik Borç ve Dersler Analizi", style: "sectionHeader" },
          { text: "\n" },
          {
            stack: [
              { text: "Karmik Borçlar", style: "subsectionHeader" },
              {
                text: typeof data.karmicDebts === 'string' ? data.karmicDebts : data.karmicDebts.join(', '),
                style: "meaningText"
              }
            ],
            margin: [0, 0, 0, 15]
          },
          {
            stack: [
              { text: "Karmik Dersler", style: "subsectionHeader" },
              {
                text: typeof data.karmicLessons === 'string' ? data.karmicLessons : data.karmicLessons.join(', '),
                style: "meaningText"
              }
            ],
            margin: [0, 0, 0, 15]
          },
          {
            table: {
              widths: ['*'],
              body: [
                [{
                  text: "Karmik borç sayıları, geçmiş yaşamlardan getirdiğimiz ve bu yaşamda çözmemiz gereken dersleri temsil eder. Bu sayılar doğum tarihinizde ve isminizde 13, 14, 16 veya 19 olarak geçer.",
                  style: "infoNote",
                  border: [false, false, false, false]
                }]
              ]
            },
            layout: 'lightHorizontalLines',
            margin: [0, 10, 0, 0]
          }
        ],
        pageBreak: 'after'
      },

      // ÇAKRA ANALİZİ SAYFASI
      {
        stack: [
          { text: "Çakra Analizi", style: "sectionHeader" },
          { text: "\n" },
          {
            text: data.chakraAnalysis,
            style: "meaningText"
          },
          { text: "\n" },
          {
            table: {
              widths: ['*'],
              body: [
                [{
                  text: "Çakralar, bedenimizdeki enerji merkezleridir. Numeroloji sayılarınız, hangi çakraların sizin için daha aktif veya dengeli olduğunu gösterebilir.",
                  style: "infoNote",
                  border: [false, false, false, false]
                }]
              ]
            },
            layout: 'lightHorizontalLines',
            margin: [0, 10, 0, 0]
          },
          { text: "\n\n" },
          {
            text: "Bu rapor sadece eğlence ve kişisel gelişim amaçlıdır. Profesyonel psikolojik veya tıbbi danışmanlık yerine geçmez.",
            style: "disclaimer",
            alignment: "center",
            margin: [0, 20, 0, 0]
          }
        ]
      }
    ],

    styles: {
      mainHeader: {
        fontSize: 22,
        bold: true,
        color: colors.primary
      },
      pageHeader: {
        fontSize: 16,
        bold: true,
        color: colors.secondary
      },
      coverTitle: {
        fontSize: 32,
        bold: true,
        color: colors.primary,
        alignment: "center",
        margin: [0, 200, 0, 0]
      },
      coverSubtitle: {
        fontSize: 18,
        italic: true,
        color: colors.secondary,
        alignment: "center",
        margin: [0, 10, 0, 0]
      },
      coverName: {
        fontSize: 20,
        bold: true,
        color: colors.dark,
        alignment: "center"
      },
      coverDate: {
        fontSize: 14,
        color: colors.text,
        alignment: "center"
      },
      coverFooter: {
        fontSize: 10,
        color: colors.secondary,
        italics: true
      },
      sectionHeader: {
        fontSize: 20,
        bold: true,
        color: colors.primary,
        margin: [0, 0, 0, 10]
      },
      subsectionHeader: {
        fontSize: 16,
        bold: true,
        color: colors.dark,
        margin: [0, 0, 0, 5]
      },
      tableHeader: {
        bold: true,
        color: colors.dark,
        fillColor: colors.light,
        margin: [0, 5, 0, 5]
      },
      tableValue: {
        margin: [0, 5, 0, 5]
      },
      infoBox: {
        margin: [0, 0, 0, 20]
      },
      infoText: {
        fontSize: 12,
        italics: true,
        color: colors.text
      },
      numberCircle: {
        fontSize: 48,
        bold: true,
        color: '#FFFFFF',
        background: colors.primary,
        border: [false, false, false, false],
        margin: [0, 0, 0, 5],
        lineHeight: 1.2
      },
      numberLabel: {
        fontSize: 14,
        color: colors.secondary,
        margin: [0, 0, 0, 10]
      },
      meaningText: {
        fontSize: 12,
        lineHeight: 1.4,
        margin: [0, 0, 0, 10]
      },
      infoNote: {
        fontSize: 11,
        italics: true,
        color: colors.secondary,
        lineHeight: 1.3
      },
      disclaimer: {
        fontSize: 10,
        italics: true,
        color: colors.secondary
      }
    }
  };

  pdfMake
    .createPdf(docDefinition)
    .download(`${data.firstName}_${data.lastName}_Numeroloji_Raporu.pdf`);
}